INSERT INTO `achievements` (`id`, `title`, `slug`, `excerpt`, `content`, `google_drive_folder_link`, `image_url`, `additional_images`, `author`, `published_at`, `is_active`, `order`, `created_at`, `updated_at`) VALUES ('10', 'Champion in Debate for Democracy!', 'champion-in-debate-for-democracy', NULL, '<p>DCGPSC debate team became champion in Debate for Democracy parliamentary debate defeating Saint Joseph College in the final.&nbsp;</p>', NULL, 'https://drive.google.com/file/d/1mfT1C2Fk3No-08x0PVzjo5zjwYesiynU/view?usp=sharing', NULL, 'barisal-admin', '2025-02-23 05:37:07', '1', '0', '2026-03-25 05:38:20', '2026-03-25 05:42:25');
INSERT INTO `achievements` (`id`, `title`, `slug`, `excerpt`, `content`, `google_drive_folder_link`, `image_url`, `additional_images`, `author`, `published_at`, `is_active`, `order`, `created_at`, `updated_at`) VALUES ('11', 'National Champion in Wildlife Olympiad!', 'national-champion-in-wildlife-olympiad', NULL, '<p>Zerin Tasnim, a student of class XII of this college, became the champion in Wildlife Olympiad 2024 at National level. Heartiest congratulations to her and her parents from DCGPSC family on this outstanding achievement.</p>', NULL, 'https://drive.google.com/file/d/1BKEveMoZvlg9DsGp5nlK-3frE0UzTmc9/view?usp=sharing', NULL, 'barisal-admin', '2024-11-10 00:38:20', '1', '0', '2026-03-25 05:40:23', '2026-03-25 05:43:02');
INSERT INTO `achievements` (`id`, `title`, `slug`, `excerpt`, `content`, `google_drive_folder_link`, `image_url`, `additional_images`, `author`, `published_at`, `is_active`, `order`, `created_at`, `updated_at`) VALUES ('12', 'Outstanding Result in HSC 2024!', 'outstanding-result-in-hsc-2024', NULL, '<p>Out of 536 students, 534 passed and 306 achieved GPA 5.00.</p><p>Congrats to the successful students and their parents from DCGPSC family!</p>', NULL, 'https://drive.google.com/file/d/1ydTYVMiipFx7sZTGYam9qhVH2ZgKQPqH/view?usp=sharing', NULL, 'barisal-admin', '2024-10-15 05:40:23', '1', '0', '2026-03-25 05:41:38', '2026-03-25 05:43:24');
