INSERT INTO `cache` (`key`, `value`, `expiration`) VALUES ('laravel-cache-global.welcome_section', 'O:25:\"App\\Models\\WelcomeSection\":33:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:16:\"welcome_sections\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:9:{s:2:\"id\";i:1;s:5:\"title\";s:53:\"Welcome to Dhaka Cantt Girls\' Public School & College\";s:7:\"content\";s:2318:\"Welcome to the website of Dhaka Cantonment Girls’ Public School and College. Our institution is dedicated to nurturing academically accomplished young women with highly developed interpersonal skills and a broad range of interests. We aim to equip our students to compete at the highest levels, both nationally and internationally, alongside the brightest and the best.\nWe are committed to providing excellent teaching and a dynamic program of extracurricular opportunities in a happy, vibrant atmosphere where every girl is encouraged to achieve her full potential. We value your feedback on our development and welcome any ideas for improvement. If you have suggestions, please email us and let us know.\n\nDhaka Cantonment Girls’ Public School & College is one of the most reputed institutions in Dhaka Cantonment. Nestled in a serene and picturesque environment, away from the hustle and bustle of the city, the college embarked on its journey in mid-2005.\nThe college offers both Bangla and English versions of study, allowing students to choose between Science and Business Studies. Each version has its own spacious building, including the pre-primary, school, and college sections. All classrooms are equipped with multimedia projectors and audio systems. Recently, a central public address system was installed for important announcements to students and teachers. Additionally, a large LED display has been installed in the college auditorium for conducting classes, presentations, and cultural programs.\nIn addition to ample classrooms, the college boasts four science laboratories and a well-stocked library. The two computer labs are fully air-conditioned and equipped with modern computers.\n\nThe institution supports extracurricular activities through its 14 clubs, including the Debate Club, English Language Club, Bangla Language and Literature Club, Arabic Language Club, Cultural Club, Sports Club, Science Club, Business Club, Math Olympiad Club, Nature Study Club, ICT Club, Art Club, Taekwondo Club, and Bangladesh National Cadet Corps club. Students are divided into four houses—Taramon Bibi House, Jahanara Imam House, Begum Rokeya House, and Begum Sufia Kamal House—for both academic and extracurricular activities. The institution has achieved remarkable success in a short span of time.\";s:9:\"image_url\";s:82:\"https://drive.google.com/file/d/1Zg2u57qunWNrkt5yAi03qYjGfZGFkqUe/view?usp=sharing\";s:11:\"button_text\";s:8:\"Details \";s:10:\"button_url\";s:29:\"https://bacpsc.edu.bd/details\";s:9:\"is_active\";i:1;s:10:\"created_at\";s:19:\"2025-11-22 19:33:10\";s:10:\"updated_at\";s:19:\"2026-03-16 10:25:55\";}s:11:\"\0*\0original\";a:9:{s:2:\"id\";i:1;s:5:\"title\";s:53:\"Welcome to Dhaka Cantt Girls\' Public School & College\";s:7:\"content\";s:2318:\"Welcome to the website of Dhaka Cantonment Girls’ Public School and College. Our institution is dedicated to nurturing academically accomplished young women with highly developed interpersonal skills and a broad range of interests. We aim to equip our students to compete at the highest levels, both nationally and internationally, alongside the brightest and the best.\nWe are committed to providing excellent teaching and a dynamic program of extracurricular opportunities in a happy, vibrant atmosphere where every girl is encouraged to achieve her full potential. We value your feedback on our development and welcome any ideas for improvement. If you have suggestions, please email us and let us know.\n\nDhaka Cantonment Girls’ Public School & College is one of the most reputed institutions in Dhaka Cantonment. Nestled in a serene and picturesque environment, away from the hustle and bustle of the city, the college embarked on its journey in mid-2005.\nThe college offers both Bangla and English versions of study, allowing students to choose between Science and Business Studies. Each version has its own spacious building, including the pre-primary, school, and college sections. All classrooms are equipped with multimedia projectors and audio systems. Recently, a central public address system was installed for important announcements to students and teachers. Additionally, a large LED display has been installed in the college auditorium for conducting classes, presentations, and cultural programs.\nIn addition to ample classrooms, the college boasts four science laboratories and a well-stocked library. The two computer labs are fully air-conditioned and equipped with modern computers.\n\nThe institution supports extracurricular activities through its 14 clubs, including the Debate Club, English Language Club, Bangla Language and Literature Club, Arabic Language Club, Cultural Club, Sports Club, Science Club, Business Club, Math Olympiad Club, Nature Study Club, ICT Club, Art Club, Taekwondo Club, and Bangladesh National Cadet Corps club. Students are divided into four houses—Taramon Bibi House, Jahanara Imam House, Begum Rokeya House, and Begum Sufia Kamal House—for both academic and extracurricular activities. The institution has achieved remarkable success in a short span of time.\";s:9:\"image_url\";s:82:\"https://drive.google.com/file/d/1Zg2u57qunWNrkt5yAi03qYjGfZGFkqUe/view?usp=sharing\";s:11:\"button_text\";s:8:\"Details \";s:10:\"button_url\";s:29:\"https://bacpsc.edu.bd/details\";s