INSERT INTO `cache` (`key`, `value`, `expiration`) VALUES ('laravel-cache-homepage.messages', 'O:39:\"Illuminate\\Database\\Eloquent\\Collection\":2:{s:8:\"\0*\0items\";a:2:{i:0;O:18:\"App\\Models\\Message\":33:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:8:\"messages\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:6:{s:2:\"id\";i:5;s:4:\"name\";s:31:\"Brig Gen Kazi Mustafizur Rahman\";s:11:\"designation\";s:13:\"SPP, ndc, psc\";s:7:\"message\";s:1369:\"Of being felt the necessity of inserting this message in our web page, I, as the new chairman, governing body of the institution, would say, this institution values the mankind first, respects the genuineness and made the students learn to face the hurdles and to become successful in life. I know the brilliant faculty members who are dedicated to their professionalism and commitment to be a part of the vibrant team of this Alma Mater.\n\nThis institution has a passionate focus on a values-based education that instills honesty, integrity, strong core of tenacity, self-respect, self-belief, compassion and mutual respect into all the students. Those treasures will embellish their capability to contribute beyond the institution into the wider community.\n\nTo attain this noble vision this institution maintain inclusive learning-teaching environment through intensive and effective care exerted to every individual student. Ostensibly, the academic results in recent years reflect its concerted endeavour to materialize her prodigious vision.\n\nThis institution is determined with its unprejudiced, altruistic, inexorable and voluntary approach to improve the professional competence and the development of women in and through our education programs. May Allah continue to bless us and our sacred vision and objective come into reality adorned in our heart and soul.\";s:9:\"image_url\";s:82:\"https://drive.google.com/file/d/1t3hzSL0QTEa3mNzGwa5-enEqwhXw6L8w/view?usp=sharing\";s:5:\"order\";i:1;}s:11:\"\0*\0original\";a:6:{s:2:\"id\";i:5;s:4:\"name\";s:31:\"Brig Gen Kazi Mustafizur Rahman\";s:11:\"designation\";s:13:\"SPP, ndc, psc\";s:7:\"message\";s:1369:\"Of being felt the necessity of inserting this message in our web page, I, as the new chairman, governing body of the institution, would say, this institution values the mankind first, respects the genuineness and made the students learn to face the hurdles and to become successful in life. I know the brilliant faculty members who are dedicated to their professionalism and commitment to be a part of the vibrant team of this Alma Mater.\n\nThis institution has a passionate focus on a values-based education that instills honesty, integrity, strong core of tenacity, self-respect, self-belief, compassion and mutual respect into all the students. Those treasures will embellish their capability to contribute beyond the institution into the wider community.\n\nTo attain this noble vision this institution maintain inclusive learning-teaching environment through intensive and effective care exerted to every individual student. Ostensibly, the academic results in recent years reflect its concerted endeavour to materialize her prodigious vision.\n\nThis institution is determined with its unprejudiced, altruistic, inexorable and voluntary approach to improve the professional competence and the development of women in and through our education programs. May Allah continue to bless us and our sacred vision and objective come into reality adorned in our heart and soul.\";s:9:\"image_url\";s:82:\"https://drive.google.com/file/d/1t3hzSL0QTEa3mNzGwa5-enEqwhXw6L8w/view?usp=sharing\";s:5:\"order\";i:1;}s:10:\"\0*\0changes\";a:0:{}s:11:\"\0*\0previous\";a:0:{}s:8:\"\0*\0casts\";a:3:{s:9:\"is_active\";s:7:\"boolean\";s:5:\"order\";s:7:\"integer\";s:5:\"style\";s:5:\"array\";}s:17:\"\0*\0classCastCache\";a:0:{}s:21:\"\0*\0attributeCastCache\";a:0:{}s:13:\"\0*\0dateFormat\";N;s:10:\"\0*\0appends\";a:0:{}s:19:\"\0*\0dispatchesEvents\";a:0:{}s:14:\"\0*\0observables\";a:0:{}s:12:\"\0*\0relations\";a:0:{}s:10:\"\0*\0touches\";a:0:{}s:27:\"\0*\0relationAutoloadCallback\";N;s:26:\"\0*\0relationAutoloadContext\";N;s:10:\"timestamps\";b:1;s:13:\"usesUniqueIds\";b:0;s:9:\"\0*\0hidden\";a:0:{}s:10:\"\0*\0visible\";a:0:{}s:11:\"\0*\0fillable\";a:11:{i:0;s:4:\"type\";i:1;s:4:\"name\";i:2;s:5:\"title\";i:3;s:4:\"slug\";i:4;s:11:\"designation\";i:5;s:9:\"image_url\";i:6;s:7:\"message\";i:7;s:4:\"link\";i:8;s:5:\"style\";i:9;s:5:\"order\";i:10;s:9:\"is_active\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}}i:1;O:18:\"App\\Models\\Message\":33:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:8:\"messages\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:6:{s:2:\"id\";i:6;s:4:\"name\";s:25:\"Col Md Mamun Azad Salehin\";s:11:\"designation\";s:9:\"afwc, psc\";s:7:\"message\";s:1739:\"Dhaka Cantonment Girls’ School and College with its rich legacy of nurturing young minds, stands as a beacon of enlightenment and progress in our community. Education is the key to empowerment and transformation. We are committed to leading our institution towards greater heights of excellence and innovation.\n\nIn today\'s fast-paced world, it is imperative that we equip our students with the necessary tools and skills to thrive in the digital age. Through the integration of technology into our teaching and learning processes, we aim to enhance the educational experience and empower our students to become lifelong learners.\n\nFurthermore, our commitment to promoting gender equality and empowerment remains unwavering. With a student body comprising bright young girls from Nursery to Class 12, we are dedicated to fostering an environment where each student can reach her full potential and emerge as a confident, enlightened individual.\n\nAt the heart of our mission lies the goal of nurturing not just academically successful individuals, but also compassionate, socially responsible citizens. We strive to instill in our students the values of tolerance, respect, and inclusivity, thus shaping them into modern, secular citizens who are capable of contributing positively to society.\n\nAs we embark on this journey together, I invite all stakeholders – students, parents, teachers, and staff members – to join hands in realizing our collective vision for the school. Let us work together to create a learning environment that is dynamic, inclusive, and conducive to the holistic development of every student. Together, let us spread the light of knowledge and empowerment, and pave the way for a brighter future for our girls.\";s:9:\"image_url\";s:82:\"https://drive.google.com/file/d/1n2TqEQgQCNmO4cmH68jcLRT0wMYb99lV/view?usp=sharing\";s:5:\"order\";i:2;}s:11:\"\0*\0original\";a:6:{s:2:\"id\";i:6;s:4:\"name\";s:25:\"Col Md Mamun Azad Salehin\";s:11:\"designation\";s:9:\"afwc, psc\";s:7:\"message\";s:1739:\"Dhaka Cantonment Girls’ School and College with its rich legacy of nurturing young minds, stands as a beacon of enlightenment and progress in our community. Education is the key to empowerment and transformation. We are committed to leading our institution towards greater heights of excellence and innovation.\n\nIn today\'s fast-paced world, it is imperative that we equip our students with the necessary tools and skills to thrive in the digital age. Through the integration of technology into our teaching and learning processes, we aim to enhance the educational experience and empower our students to become lifelong learners.\n\nFurthermore, our commitment to promoting gender equality and empowerment remains unwavering. With a student body comprising bright young girls from Nursery to Class 12, we are dedicated to fostering an environment where each student can reach her full potential and emerge as a confident, enlightened individual.\n\nAt the heart of our mission lies the goal of nurturing not just academically successful individuals, but also compassionate, socially responsible citizens. We strive to instill in our students the values of tolerance, respect, and inclusivity, thus shaping them into modern, secular citizens who are capable of contributing positively to society.\n\nAs we embark on this journey together, I invite all stakeholders – students, parents, teachers, and staff members – to join hands in realizing our collective vision for the school. Let us work together to create a learning environment that is dynamic, inclusive, and conducive to the holistic development of every student. Together, let us spread the light of knowledge and empowerment, and pave the way for a brighter future for our girls.\";s:9:\"image_url\";s:82:\"https://drive.google.com/file/d/1n2TqEQgQCNmO4cmH68jcLRT0wMYb99lV/view?usp=sharing\";s:5:\"order\";i:2;}s:10:\"\0*\0changes\";a:0:{}s:11:\"\0*\0previous\";a:0:{}s:8:\"\0*\0casts\";a:3:{s:9:\"is_active\";s:7:\"boolean\";s:5:\"order\";s:7:\"integer\";s:5:\"style\";s:5:\"array\";}s:17:\"\0*\0classCastCache\";a:0:{}s:21:\"\0*\0attributeCastCache\";a:0:{}s:13:\"\0*\0dateFormat\";N;s:10:\"\0*\0appends\";a:0:{}s:19:\"\0*\0dispatchesEvents\";a:0:{}s:14:\"\0*\0observables\";a:0:{}s:12:\"\0*\0relations\";a:0:{}s:10:\"\0*\0touches\";a:0:{}s:27:\"\0*\0relationAutoloadCallback\";N;s:26:\"\0*\0relationAutoloadContext\";N;s:10:\"timestamps\";b:1;s:13:\"usesUniqueIds\";b:0;s:9:\"\0*\0hidden\";a:0:{}s:10:\"\0*\0visible\";a:0:{}s:11:\"\0*\0fillable\";a:11:{i:0;s:4:\"type\";i:1;s:4:\"name\";i: