INSERT INTO `messages` (`id`, `type`, `name`, `title`, `slug`, `designation`, `image_url`, `image`, `message`, `link`, `style`, `order`, `is_active`, `created_at`, `updated_at`) VALUES ('5', 'Chairman', 'Brig Gen Kazi Mustafizur Rahman', 'Message of the Chairman', 'brig-gen-kazi-mustafizur-rahman', 'SPP, ndc, psc', 'https://drive.google.com/file/d/1t3hzSL0QTEa3mNzGwa5-enEqwhXw6L8w/view?usp=sharing', NULL, 'Of being felt the necessity of inserting this message in our web page, I, as the new chairman, governing body of the institution, would say, this institution values the mankind first, respects the genuineness and made the students learn to face the hurdles and to become successful in life. I know the brilliant faculty members who are dedicated to their professionalism and commitment to be a part of the vibrant team of this Alma Mater.\n\nThis institution has a passionate focus on a values-based education that instills honesty, integrity, strong core of tenacity, self-respect, self-belief, compassion and mutual respect into all the students. Those treasures will embellish their capability to contribute beyond the institution into the wider community.\n\nTo attain this noble vision this institution maintain inclusive learning-teaching environment through intensive and effective care exerted to every individual student. Ostensibly, the academic results in recent years reflect its concerted endeavour to materialize her prodigious vision.\n\nThis institution is determined with its unprejudiced, altruistic, inexorable and voluntary approach to improve the professional competence and the development of women in and through our education programs. May Allah continue to bless us and our sacred vision and objective come into reality adorned in our heart and soul.', NULL, NULL, '1', '1', '2026-03-13 15:42:51', '2026-03-16 06:16:07');
INSERT INTO `messages` (`id`, `type`, `name`, `title`, `slug`, `designation`, `image_url`, `image`, `message`, `link`, `style`, `order`, `is_active`, `created_at`, `updated_at`) VALUES ('6', 'Principal', 'Col Md Mamun Azad Salehin', 'Message of the Principal', 'col-md-mamun-azad-salehin', 'afwc, psc', 'https://drive.google.com/file/d/1n2TqEQgQCNmO4cmH68jcLRT0wMYb99lV/view?usp=sharing', NULL, 'Dhaka Cantonment Girls’ School and College with its rich legacy of nurturing young minds, stands as a beacon of enlightenment and progress in our community. Education is the key to empowerment and transformation. We are committed to leading our institution towards greater heights of excellence and innovation.\n\nIn today\'s fast-paced world, it is imperative that we equip our students with the necessary tools and skills to thrive in the digital age. Through the integration of technology into our teaching and learning processes, we aim to enhance the educational experience and empower our students to become lifelong learners.\n\nFurthermore, our commitment to promoting gender equality and empowerment remains unwavering. With a student body comprising bright young girls from Nursery to Class 12, we are dedicated to fostering an environment where each student can reach her full potential and emerge as a confident, enlightened individual.\n\nAt the heart of our mission lies the goal of nurturing not just academically successful individuals, but also compassionate, socially responsible citizens. We strive to instill in our students the values of tolerance, respect, and inclusivity, thus shaping them into modern, secular citizens who are capable of contributing positively to society.\n\nAs we embark on this journey together, I invite all stakeholders – students, parents, teachers, and staff members – to join hands in realizing our collective vision for the school. Let us work together to create a learning environment that is dynamic, inclusive, and conducive to the holistic development of every student. Together, let us spread the light of knowledge and empowerment, and pave the way for a brighter future for our girls.', NULL, NULL, '2', '1', '2026-03-13 15:45:43', '2026-03-16 09:59:02');
