INSERT INTO `news_events` (`id`, `title`, `slug`, `excerpt`, `content`, `image_url`, `additional_images`, `author`, `is_active`, `published_at`, `created_at`, `updated_at`) VALUES ('5', 'Annual Sport - 2026', 'annual-sport-2026', NULL, '<p>The biggest event of the year, The Interhouse Annual Sport - 2026, took place in a festive mood. The campus took a colorful look for that event, so as the students. There were gaming events for the students, the parents, and the guests, Parade, PT, Taekwondo, Dress as You Like, and a colorful display. Major General Md Sajedur Rahman , ndu, psc, Military Secretary, Bangladesh Army, was present as the chief guest while Fatema Zohura was the special guest. The special guest distributed prizes among the winners, and the chief guest awarded the group champions and the winner houses.&nbsp;</p><p>The program ended with the attenuation of the flags.</p>', 'https://drive.google.com/file/d/1JRu5I8v4w1HLvh--h4NFUCihIZaBdczK/view?usp=sharing', NULL, 'barisal-admin', '1', '2026-01-22 05:26:42', '2026-03-25 05:28:39', '2026-03-25 05:44:19');
INSERT INTO `news_events` (`id`, `title`, `slug`, `excerpt`, `content`, `image_url`, `additional_images`, `author`, `is_active`, `published_at`, `created_at`, `updated_at`) VALUES ('6', 'Celebrating the Outstanding HSC Results with our Student', 'celebrating-the-outstanding-hsc-results-with-our-student', NULL, '<p>Congratulations to all HSC achievers! Your hard work, patience, and dedication have paid off. Wishing you all the best for your next chapter!</p>', 'https://drive.google.com/file/d/1kBIoENKw_wXL2JVA1OEWs7tOY_j1K1HQ/view?usp=sharing', NULL, 'barisal-admin', '1', '2025-10-10 05:28:38', '2026-03-25 05:31:11', '2026-03-25 05:44:59');
INSERT INTO `news_events` (`id`, `title`, `slug`, `excerpt`, `content`, `image_url`, `additional_images`, `author`, `is_active`, `published_at`, `created_at`, `updated_at`) VALUES ('7', 'Celebrating the Outstanding SSC Results with our Student', 'celebrating-the-outstanding-ssc-results-with-our-student', NULL, '<p>A proud moment for our school.</p><p>Celebrating the outstanding SSC results with our students, teachers and honourable Principal sir.</p><p>Congratulations to all students!</p>', 'https://drive.google.com/file/d/1oDl4njObYgi75w6L3zgGsSG_ukulT4yX/view?usp=sharing', NULL, 'barisal-admin', '1', '2025-07-10 05:31:10', '2026-03-25 05:32:38', '2026-03-25 05:45:24');
