INSERT INTO `pages` (`id`, `title`, `slug`, `image_url`, `content`, `html_content`, `buttons`, `bottom_content`, `meta_title`, `meta_description`, `is_published`, `menu_id`, `published_at`, `created_at`, `updated_at`) VALUES ('12', 'Button', 'button', NULL, '\n\n\nনিচের বাট ক্লিক করুন', 'নিচের বাট ক্লিক করুননিচের বাট ক্লিক করুননিচের বাট ক্লিক করুননিচের বাট ক্লিক করুন', '[{\"url\": \"https://facebook.com\", \"icon\": \"fa-link\", \"text\": \"Online Admission \", \"color\": \"danger\", \"open_new_tab\": false}]', 'নিচের বাট ক্লিক করুননিচের বাট ক্লিক করুননিচের বাট ক্লিক করুননিচের বাট ক্লিক করুন', NULL, NULL, '1', '33', '2025-12-17 12:41:55', '2025-12-17 12:44:28', '2025-12-17 12:57:11');
INSERT INTO `pages` (`id`, `title`, `slug`, `image_url`, `content`, `html_content`, `buttons`, `bottom_content`, `meta_title`, `meta_description`, `is_published`, `menu_id`, `published_at`, `created_at`, `updated_at`) VALUES ('20', 'At a Glance', 'at-a-glance', NULL, 'Dhaka Cantt Girls’ Public School & College is one of the most reputed colleges in Dhaka City. The College, full of scenic beauty and free from din and bustle of the city, launched it journey in the middle of 2005. Lt Col Zahid Hossain (retired as Brig Gen) was appointed as the founder principal.\n\nApart from sufficient classrooms, the college has four science laboratories and a modern library. The library of this institute is fully air conditioned having more than 5000 volumes and internet facilities. The computer lab of this institution is enriched with modern amenities having 30 computers. The institution has its own clubs for running extracurricular activities. There are four different houses in which the students are categorized for academic and extracurricular activities. It has showed its best with in the short span of time.\n\nPresently Brig Gen Md Abdur Razzak, SUP, ndc, psc is the Chairman of the Governing Body and Col Md Mamun Azad Salehin, afwc, psc is the Principal of the institution. Currently Principal, Vice Principal, 36 Teachers in College section, 80 Teachers in School section, 29 Office Staff, 60 MLSS are working here. The classes are being conducted from Nursery to class XII in Bangla Version and Nursery to class IX in English Version.', NULL, '[]', NULL, NULL, NULL, '1', NULL, '2025-12-29 17:56:03', '2025-12-29 17:58:17', '2026-03-16 10:38:36');
INSERT INTO `pages` (`id`, `title`, `slug`, `image_url`, `content`, `html_content`, `buttons`, `bottom_content`, `meta_title`, `meta_description`, `is_published`, `menu_id`, `published_at`, `created_at`, `updated_at`) VALUES ('21', 'History', 'history', NULL, 'Dhaka Cantonment Girls\' Public School and College started its journey in August 2005 intending to create dynamic womenfolk for future Bangladesh. Lt Col Md Zahid Hossain, AEC (Retd as Brig Gen) was postes as first Principal. Initial works were started under the supervision of the AHQ Education Directorate. Brig Gen Md. Golam Hossain the then Comd, Army Sig Bde was nominated as the first Chairman of the Governing Body of the institution by the then Chief of Army Staff\n\n\nThe first admission test was arranged in Dec 2005. Classes were started from 1 January 2006 with 17 Sections from class II to VII. The School was formally inaugurated by Chief of Army Staff Gen Moin U Ahmed, NDC, PSC on 02 March 2006.', NULL, '[]', NULL, NULL, NULL, '1', NULL, '2025-12-29 17:58:17', '2025-12-29 18:00:31', '2026-03-16 10:38:59');
INSERT INTO `pages` (`id`, `title`, `slug`, `image_url`, `content`, `html_content`, `buttons`, `bottom_content`, `meta_title`, `meta_description`, `is_published`, `menu_id`, `published_at`, `created_at`, `updated_at`) VALUES ('22', 'Why study DCGPSC', 'Why study DCGPSC', NULL, 'Dhaka Cantt Girls’ Public School & College in an emerging institute having all facilities for students, and the teachers of the institute are very experienced and knowledgeable. \n\nAcademic Facilities \n\nThe Institute has its own campus sufficient class rooms, the institution is enriched with a modern library,four labs, two play grounds and a small children’s park.  The School is surrounded by lakes from three sides that make the environment solitary. \n\nExcellent Result \n\nEvery year the institute shows extra ordinary result in different public exams. A number of students achieve position in the board each year. Many of the students get admitted in the public Universities and other institutions every year for higher studies. \n\nStrong cultural Identity\n\nWithin the short span of time, the institution earned a reputation for its cultural activities. Students of this institute take part in debate competitions arranged by the government of Bangladesh and Army Headquarters and achieve different awards every year. Apart from this, the students of this college win prizes in essay competitions arranged nationally from time to time. \n\nLeader in Games & Sports\n\nEvery year many Students Participate in different tournament including athletics, handball, cricket etc. Our team became champion in Inter College Girls’ Cricket, Handball and Athletics Tournament several times. \n\nVeteran Teaching Staffs \n\nWe have 92 experienced and qualified teachers who create a congenial atmospleve  in the class to make the students efficient and morally developed.', NULL, '[]', NULL, NULL, NULL, '1', NULL, '2025-12-29 18:00:31', '2025-12-29 18:02:15', '2026-03-26 11:29:27');
INSERT INTO `pages` (`id`, `title`, `slug`, `image_url`, `content`, `html_content`, `buttons`, `bottom_content`, `meta_title`, `meta_description`, `is_published`, `menu_id`, `published_at`, `created_at`, `updated_at`) VALUES ('23', 'Governing Body', 'governing-body', NULL, '.', '<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Governing Body - RCESC</title>\n    <style>\n        .gb-container {\n            max-width: 1100px;\n            margin: 0 auto;\n            padding: 20px;\n            font-family: \'Arial\', sans-serif;\n            text-align: center;\n        }\n\n        .gb-title {\n            color: #1a5c2e;\n            font-size: 32px;\n            margin-bottom: 40px;\n            border-bottom: 2px solid #1a5c2e;\n            display: inline-block;\n            padding-bottom: 10px;\n        }\n\n        /* Top Single Card */\n        .chief-section {\n            display: flex;\n            justify-content: center;\n            margin-bottom: 40px;\n        }\n\n        /* Grid for 3 columns */\n        .members-grid {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr); /* এক লাইনে ৩টি */\n            gap: 25px;\n        }\n\n        .member-card {\n            background: #fff;\n            border: 1px solid #ddd;\n            border-top: 5px solid #1a5c2e;\n            border-radius: 8px;\n            padding: 20px;\n            box-shadow: 0 4px 10px rgba(0,0,0,0.05);\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n        }\n\n        .chief-card {\n            width: 350px; /* Chief Patron একটু বড় */\n            border-top-color: #d4af37; /* Gold border */\n        }\n\n        .member-photo {\n            width: 140px;\n            height: 160px;\n            background-color: #f0f0f0;\n            margin-bottom: 15px;\n            border-radius: 5px;\n            object-fit: cover;\n            border: 1px solid #eee;\n        }\n\n        .m-name {\n            font-size: 16px;\n            font-weight: bold;\n            color: #333;\n            margin-bottom: 8px;\n            line-height: 1.3;\n        }\n\n        .m-desig {\n            font-size: 14px;\n            color: #666;\n            margin-bottom: 12px;\n            min-height: 40px; /* এলাইনমেন্ট ঠিক রাখার জন্য */\n        }\n\n        .m-role {\n            background: #1a5c2e;\n            color: #fff;\n            font-size: 12px;\n            padding: 5px 15px;\n            border-radius: 20px;\n            text-transform: uppercase;\n        }\n\n        /* Mobile Responsive */\n        @media (max-width: 900px) {\n            .members-grid { grid-template-columns: repeat(2, 1fr); }\n        }\n        @media (max-width: 600px) {\n            .members-grid { grid-template-columns: 1fr; }\n            .chief-card { width: 100%; }\n        }\n    </style>\n</head>\n<body>\n\n<div class=\"gb-container\">\n    <h1 class=\"gb-title\">GOVERNING BODY</h1>\n\n    <div class=\"chief-section\">\n        <div class=\"member-card chief-card\">\n            <img src=\"https://drive.google.com/thumbnail?id=1c1S0LftMeWrKugw7OMleUpNwIHX0Y7Gq&sz=w800\" alt=\"Chief Patron\" class=\"member-photo\">\n            <div class=\"m-name\">Maj Gen Mohammad Asadullah Minhazul Alam, ndu, psc, PhD</div>\n            <div class=\"m-desig\">GOC, 10 Inf Div & Area Commander, Cox\'s Bazar Area</div>\n            <div class=\"m-role\">Chief Patron</div>\n        </div>\n    </div>\n    <div class=\"members-grid\">\n        <div class=\"member-card\">\n            <img src=\"https://drive.google.com/thumbnail?id=1me1hfGslY5SCT-66zUWv4zHgZeJh89C0&sz=w800\"  alt=\"Chairman\" class=\"member-photo\">\n            <div class=\"m-name\">Brig Gen Md Khademul Bashar, PBGMS, psc</div>\n            <div class=\"m-desig\">Commander, 65 Infantry Brigade</div>\n            <div class=\"m-role\">Chairman</div>\n        </div>\n\n        <div class=\"member-card\">\n            <img src=\"https://drive.google.com/thumbnail?id=1rLSq0VGMdJ5N4AeIT0rRQMkKBPMt8Ig0&sz=w800\" alt=\"Member Secretary\" class=\"member-photo\">\n            <div class=\"m-name\">Lecturer H. M Syeedur Rahman</div>\n            <div class=\"m-desig\">Teachers Representative</div>\n            <div class=\"m-role\">Member</div>\n        </div>\n        <div class=\"member-card\">\n            <img src=\"https://drive.google.com/thumbnail?id=1kIBpAsS61YOuE30ywg3BXmdsR8lYGOiP&sz=w800\" alt=\"Member\" class=\"member-photo\">\n            <div class=\"m-name\">Sr. Teacher Tasnim Sauda Saki</div>\n            <div class=\"m-desig\">Teachers Representative</div>\n            <div class=\"m-role\">Member</div>\n        </div>\n        \n        <div class=\"member-card\">\n            <img src=\"https://drive.google.com/thumbnail?id=1WB4V-25Tg0Lx0MqC95NQ6HSBXJG9VP5M&sz=w800\" alt=\"Member\" class=\"member-photo\">\n            <div class=\"m-name\">Asst Teacher Mohammad Saifullah</div>\n            <div class=\"m-desig\">Teachers Representative</div>\n            <div class=\"m-role\">Member</div>\n        </div>\n\n<div class=\"member-card\">\n            <img src=\"https://drive.google.com/thumbnail?id=1rLSq0VGMdJ5N4AeIT0rRQMkKBPMt8Ig0&sz=w800\" alt=\"Member\" class=\"member-photo\">\n            <div class=\"m-name\">Lt Col M Iqbal Khalid, psc, ADST</div>\n            <div class=\"m-desig\">Guardian Representative</div>\n            <div class=\"m-role\">Member</div>\n        </div>\n\n<div class=\"member-card\">\n            <img src=\"https://drive.google.com/thumbnail?id=1rLSq0VGMdJ5N4AeIT0rRQMkKBPMt8Ig0&sz=w800\" alt=\"Member\" class=\"member-photo\">\n            <div class=\"m-name\">Lt Col Z M Mahmudul Islam, psc, Engrs</div>\n            <div class=\"m-desig\">Guardian Representative</div>\n            <div class=\"m-role\">Member</div>\n        </div>\n\n      <div class=\"member-card\">\n            <img src=\"https://drive.google.com/thumbnail?id=1rLSq0VGMdJ5N4AeIT0rRQMkKBPMt8Ig0&sz=w800\" alt=\"Member\" class=\"member-photo\">\n            <div class=\"m-name\">Asst Prof Shormin Siddiqa Lima</div>\n            <div class=\"m-desig\">Guardian Representative</div>\n            <div class=\"m-role\">Member</div>\n        </div>\n\n        <div class=\"member-card\">\n              <img src=\"https://drive.google.com/thumbnail?id=1rLSq0VGMdJ5N4AeIT0rRQMkKBPMt8Ig0&sz=w800\" alt=\"Member\" class=\"member-photo\">\n              <div class=\"m-name\">Lt Col Mahtab Khan, psc</div>\n              <div class=\"m-desig\">Co-opt Member</div>\n              <div class=\"m-role\">Member</div>\n        </div>\n\n       <div class=\"member-card\">\n              <img src=\"https://drive.google.com/thumbnail?id=1rLSq0VGMdJ5N4AeIT0rRQMkKBPMt8Ig0&sz=w800\" alt=\"Member\" class=\"member-photo\">\n              <div class=\"m-name\">Maj M Zahid Hassan Maroof, AEC</div>\n              <div class=\"m-desig\">Co-opt Member</div>\n              <div class=\"m-role\">Member</div>\n        </div>\n\n <div class=\"member-card\">\n              <img src=\"https://drive.google.com/thumbnail?id=12usXBZF8Qxib4L0xHjba32B3knfgNI8a&sz=w800\" alt=\"Member\" class=\"member-photo\">\n              <div class=\"m-name\">Maj Md Rashedul Kabir,Inf</div>\n              <div class=\"m-desig\">Co-opt Member</div>\n              <div class=\"m-role\">Member</div>\n        </div>\n\n <div class=\"member-card\">\n              <img src=\"https://drive.google.com/thumbnail?id=1QCP4gbU9jkxdMYPGSfqvhM7vd0TXHVXu&sz=w800\" alt=\"Member\" class=\"member-photo\">\n              <div class=\"m-name\">Lt Col Md Abdur Rahim, M Phil, AEC</div>\n              <div class=\"m-desig\">Principal & </div>\n              <div class=\"m-role\"> Member Secretary</div>\n        </div>\n    </div>\n</div>\n\n</body>\n</html>', '[]', NULL, NULL, NULL, '1', '44', '2025-12-29 18:15:36', '2025-12-29 18:16:13', '2025-12-29 19:24:52');
