INSERT INTO `pages` (`id`, `title`, `slug`, `image_url`, `content`, `html_content`, `buttons`, `bottom_content`, `meta_title`, `meta_description`, `is_published`, `menu_id`, `published_at`, `created_at`, `updated_at`) VALUES ('28', 'Class Room', 'class-room', 'https://drive.google.com/file/d/1gJQpSK96iF7meb4VKTSuHh8d3tH3BiBV/view?usp=sharing', 'The Institution has 68 well decorated classrooms. The Classrooms Present a learner friendly environment. Besides, there are 52 multimedia classrooms in the institution. Here, teachers can take classes using multimedia projector and digital content.', NULL, '[]', NULL, NULL, NULL, '1', '55', '2025-12-29 23:16:36', '2025-12-29 23:20:45', '2026-03-26 10:19:38');
INSERT INTO `pages` (`id`, `title`, `slug`, `image_url`, `content`, `html_content`, `buttons`, `bottom_content`, `meta_title`, `meta_description`, `is_published`, `menu_id`, `published_at`, `created_at`, `updated_at`) VALUES ('29', 'Indoor Game', 'indoor-game', NULL, '<img src=\"https://drive.google.com/thumbnail?id=1FACC3BelDSHaQqLXPItbwA4kv70gHlwT&sz=w800\" alt=\"Admission\" class=\"circular-photo\">', NULL, '[]', NULL, NULL, NULL, '1', '56', '2025-12-29 23:20:44', '2025-12-29 23:22:59', '2025-12-29 23:27:53');
