INSERT INTO `pages` (`id`, `title`, `slug`, `image_url`, `content`, `html_content`, `buttons`, `bottom_content`, `meta_title`, `meta_description`, `is_published`, `menu_id`, `published_at`, `created_at`, `updated_at`) VALUES ('31', 'Library', 'library', 'https://drive.google.com/file/d/1M8fi1O-D0rY2zaPCKeJ0niIrQ2iHgMWR/view?usp=sharing', 'The Institution has a pally air conditioned modern library with seating arrangement of 100 Students. It is enriched with five thousand books. It is named as “Lt Col Zayed Memorial Library and Information Centre” recognizing his contribution for establishing the library.', NULL, '[]', NULL, NULL, NULL, '1', '58', '2025-12-29 23:24:21', '2025-12-29 23:25:47', '2026-03-26 10:48:36');
INSERT INTO `pages` (`id`, `title`, `slug`, `image_url`, `content`, `html_content`, `buttons`, `bottom_content`, `meta_title`, `meta_description`, `is_published`, `menu_id`, `published_at`, `created_at`, `updated_at`) VALUES ('32', 'Lab', 'lab', 'https://drive.google.com/file/d/1WuKx3JwBkJhxItC2IvWmnSnjuYsHxx77/view?usp=sharing', 'The institution has four laboratories. \nThey are: \n\n\n1.    Physics Lab \n2.    Chemistry Lab \n3.    Biology Lab\n4.    Computer Lab \nAll the labs are newly renovated and are equipped with all necessary instruments and modern amenities. Computer lab is fully air conditioned and is facilitated with internet access students can also avail  \n\nN-Computing system in the Lab. ', NULL, '[]', NULL, NULL, NULL, '1', '59', '2025-12-29 23:25:47', '2025-12-29 23:27:19', '2026-03-26 10:22:27');
