INSERT INTO `pages` (`id`, `title`, `slug`, `image_url`, `content`, `html_content`, `buttons`, `bottom_content`, `meta_title`, `meta_description`, `is_published`, `menu_id`, `published_at`, `created_at`, `updated_at`) VALUES ('44', 'Mission & Vision', 'mission-vision', NULL, '[](https://drive.google.com/file/d/1voEn52WRO9HonH22lKyyXUvzUauSdf3H/view?usp=sharing)\n# Mission & Vision of DCGPSC\n\nDhaka Cantt Girls’ Public School & College seeks to produce academically well-educated young women, with highly developed interpersonal skills and a broad range of interests, who can compete at any level with the brightest and the best, both nationally and internationally.\n\nObjectives\n1. 1.To make each girl as an asset to ensure their participation in various social and cultural activities.\n2. 2.To inspire each student to exhibit honesty, discipline, wisdom, competence, humanity and dedication in their character.\n3. 3.To inculcate dynamic leadership qualities in each student through various co-curricular activities\n4. 4.To enable the students to go ahead and introduce them with the modern technology.\n5. 5.To make a conscious citizen inspired by the feelings of humanity, honesty, patriotism and our liberation war.\n6. 6.To make a promised citizen inspired by the feelings of solidarity, diversity and mutual harmony.', NULL, '[]', NULL, NULL, NULL, '1', '65', '2026-03-23 15:22:57', '2026-03-23 15:23:48', '2026-03-23 15:34:30');
